// Facebook Marketing API helper functions
class FacebookMarketingAPIHelper {
  constructor(accessToken, adAccountId) {
    this.accessToken = accessToken;
    this.adAccountId = adAccountId;
    this.baseUrl = 'https://graph.facebook.com/v18.0';
  }

  async createCustomAudience(config) {
    const response = await fetch(`${this.baseUrl}/act_${this.adAccountId}/customaudiences`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${this.accessToken}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        name: config.name,
        description: config.description || '',
        rule: JSON.stringify(config.rules),
        retention_days: config.retention_days || 30
      })
    });

    if (!response.ok) {
      throw new Error(`Failed to create custom audience: ${response.statusText}`);
    }

    return response.json();
  }

  async getCustomAudiences() {
    const response = await fetch(`${this.baseUrl}/act_${this.adAccountId}/customaudiences?fields=name,description,rule,retention_days,time_created,data_source&limit=50`, {
      headers: {
        'Authorization': `Bearer ${this.accessToken}`
      }
    });

    if (!response.ok) {
      throw new Error(`Failed to get custom audiences: ${response.statusText}`);
    }

    return response.json();
  }

  async deleteCustomAudience(audienceId) {
    const response = await fetch(`${this.baseUrl}/${audienceId}`, {
      method: 'DELETE',
      headers: {
        'Authorization': `Bearer ${this.accessToken}`
      }
    });

    if (!response.ok) {
      throw new Error(`Failed to delete custom audience: ${response.statusText}`);
    }

    return response.json();
  }

  // Generate Facebook Pixel code for Shopify
  generatePixelCode(pixelId, customData = {}) {
    const baseCode = `
<!-- Facebook Pixel Code -->
<script>
!function(f,b,e,v,n,t,s)
{if(f.fbq)return;n=f.fbq=function(){n.callMethod?
n.callMethod.apply(n,arguments):n.queue.push(arguments)};
if(!f._fbq)f._fbq=n;n.push=n;n.loaded=!0;n.version='2.0';
n.queue=[];t=b.createElement(e);t.async=!0;
t.src=v;s=b.getElementsByTagName(e)[0];
s.parentNode.insertBefore(t,s)}(window, document,'script',
'https://connect.facebook.net/en_US/fbevents.js');
fbq('init', '${pixelId}');
fbq('track', 'PageView');
</script>
<noscript><img height="1" width="1" style="display:none"
src="https://www.facebook.com/tr?id=${pixelId}&ev=PageView&noscript=1"
/></noscript>
<!-- End Facebook Pixel Code -->`;

    const customDataCode = customData ? `
<script>
// Custom event tracking
fbq('track', 'InitiateCheckout', ${JSON.stringify(customData)});
fbq('track', 'Purchase', ${JSON.stringify(customData)});
</script>` : '';

    return baseCode + customDataCode;
  }
}

